def dedup_report(rows, key='id'):
    seen = {}
    unique = []
    conflicts = []
    for row in rows:
        k = row[key]
        if k not in seen:
            seen[k] = row
            unique.append(row)
        elif row != seen[k]:
            conflicts.append(row)
    return {'unique': unique, 'conflicts': conflicts}
